import * as asserts from "assert";
import chalk from "chalk";

function record<T extends (...args: any) => any>(fn: T): T {
  return function (this: any) {
    const args = Array.from(arguments);
    const result = fn.apply(this, args);

    // 记录执行情况
    const [args1, args2, args3, ...restArgs] = args;
    const pass = result === undefined || result === null || result === true;
    console.log(
      chalk.green(
        `Assert ${args1} ${fn?.name} ${args2 ?? ""} ${args3 ?? ""} ${
          pass ? "passed" : "failed"
        }`
      )
    );

    return result;
  } as T;
}

export const initAssert = (assert: any) => {
  assert.deepEqual = record(assert.deepEqual);
  assert.deepStrictEqual = record(assert.deepStrictEqual);
  assert.doesNotMatch = record(assert.doesNotMatch);
  assert.doesNotReject = record(assert.doesNotReject);
  assert.doesNotThrow = record(assert.doesNotThrow);
  assert.fail = record(assert.fail);
  assert.ifError = record(assert.ifError);
  assert.match = record(assert.match);
  assert.notDeepEqual = record(assert.notDeepEqual);
  assert.notDeepStrictEqual = record(assert.notDeepStrictEqual);
  assert.notStrictEqual = record(assert.notStrictEqual);
  assert.rejects = record(assert.rejects);
  assert.strictEqual = record(assert.strictEqual);
  assert.throws = record(assert.throws);
  assert.notEqual = record(assert.notEqual);
  assert.ok = record(assert.ok);
  assert.equal = record(assert.equal);
};


export const assert = initAssert(asserts)

